-- ============================================================================
-- LOGOS LIGHT — Quiz Seed Questions (MVP)
-- ============================================================================
-- Covers: John 1–3, Mark 1, Genesis 1–3, Romans 1
-- Per chapter: 10–15 questions per stage (1–4), 5–10 for stage 5.
-- Each quiz attempt randomly pulls 5 from the correct pool.
--
-- Book numbers: Genesis=1, Mark=41, John=43, Romans=45
-- ============================================================================

-- ============================================================================
-- JOHN 1
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1: Very Easy
(43,1,1,'What does John 1:1 say was "in the beginning"?',
 '["The Word","The Spirit","The Law","The Gospel"]','The Word',
 'John 1:1 says "In the beginning was the Word."'),
(43,1,1,'According to John 1, who bore witness about the light?',
 '["John the Baptist","Peter","Moses","Elijah"]','John the Baptist',
 'John the Baptist was sent to bear witness about the light (John 1:6–8).'),
(43,1,1,'Where was "the Word" in the beginning, according to John 1:1?',
 '["With God","In heaven","In Israel","In the temple"]','With God',
 '"In the beginning was the Word, and the Word was with God."'),
(43,1,1,'What did John 1:14 say the Word became?',
 '["Flesh","Spirit","Light","Voice"]','Flesh',
 '"The Word became flesh and dwelt among us."'),
(43,1,1,'What did John say he was not, when asked if he was the Christ?',
 '["He said he was not","He said he was","He refused to answer","He was silent"]','He said he was not',
 'John clearly stated "I am not the Christ" (John 1:20).'),
(43,1,1,'What title did John use to describe Jesus in John 1:29?',
 '["Lamb of God","King of Israel","Son of David","Light of the World"]','Lamb of God',
 '"Behold, the Lamb of God, who takes away the sin of the world!" (John 1:29).'),
(43,1,1,'What new name did Jesus give Simon?',
 '["Peter (Cephas)","Paul","James","Stephen"]','Peter (Cephas)',
 'Jesus said "You shall be called Cephas" (which means Peter) in John 1:42.'),
(43,1,1,'What did Philip tell Nathanael when he invited him to see Jesus?',
 '["Come and see","Read and believe","Follow and learn","Ask and receive"]','Come and see',
 'Philip said "Come and see" in John 1:46.'),
(43,1,1,'Who did Jesus see coming toward him and called "Lamb of God"?',
 '["Jesus himself saw John come to be baptized","None — John spoke about Jesus","Peter came first","Andrew arrived"]','None — John spoke about Jesus',
 'John the Baptist said "Behold, the Lamb of God" when he saw Jesus coming toward him.'),
(43,1,1,'From what town were Andrew and Peter?',
 '["Bethsaida","Nazareth","Capernaum","Jerusalem"]','Bethsaida',
 'Andrew and Peter were from Bethsaida (John 1:44).'),

-- Stage 2: Easy
(43,1,2,'Who was the first person Jesus called as a disciple in John 1?',
 '["Andrew","Peter","Philip","Nathanael"]','Andrew',
 'Andrew, one of the two who heard John and followed Jesus, is named first (John 1:40).'),
(43,1,2,'In John 1, John the Baptist described himself as "the voice of one crying in the wilderness." What did he say to do?',
 '["Make straight the way of the Lord","Repent of your sins","Follow the Lamb","Come to the temple"]','Make straight the way of the Lord',
 'John quoted Isaiah: "Make straight the way of the Lord" (John 1:23).'),
(43,1,2,'What did Nathanael say about Nazareth when Philip told him about Jesus?',
 '["Can anything good come out of Nazareth?","Nazareth is too far","I know no one from Nazareth","Nazareth is not in the prophecy"]','Can anything good come out of Nazareth?',
 'Nathanael said "Can anything good come out of Nazareth?" in John 1:46.'),
(43,1,2,'What did Jesus promise Nathanael he would see in John 1:51?',
 '["Angels ascending and descending on the Son of Man","The temple rebuilt","Water turned to wine","The resurrection"]','Angels ascending and descending on the Son of Man',
 '"You will see heaven opened, and the angels of God ascending and descending on the Son of Man" (John 1:51).'),
(43,1,2,'The Word was the light of men. What did John 1:5 say about the darkness?',
 '["The darkness has not overcome it","The darkness fled from it","The darkness did not exist","The darkness became light"]','The darkness has not overcome it',
 '"The light shines in the darkness, and the darkness has not overcome it" (John 1:5).'),
(43,1,2,'John 1:12 says that to all who received Jesus, he gave the right to become what?',
 '["Children of God","Disciples","Apostles","Priests"]','Children of God',
 '"To all who received him, he gave the right to become children of God" (John 1:12).'),
(43,1,2,'Who did John say was coming after him whose sandal strap he was not worthy to untie?',
 '["Jesus","The Messiah (unspecified)","Elijah","The Prophet"]','Jesus',
 'John 1:27 says "he who comes after me, the strap of whose sandal I am not worthy to untie."'),
(43,1,2,'John 1:17 contrasts the law given through Moses with grace and truth that came through whom?',
 '["Jesus Christ","The Holy Spirit","The Prophets","John the Baptist"]','Jesus Christ',
 '"Grace and truth came through Jesus Christ" (John 1:17).'),
(43,1,2,'When Andrew found his brother Simon and said "We have found the Messiah," what does "Messiah" mean according to John 1:41?',
 '["Christ","Savior","Lord","Teacher"]','Christ',
 '"We have found the Messiah (which means Christ)" (John 1:41).'),
(43,1,2,'What did Nathanael call Jesus after Jesus said he had seen him under the fig tree?',
 '["Rabbi, Son of God, King of Israel","Teacher, Messiah, Prophet","Lord, Savior, King","The Word, The Light, The Way"]','Rabbi, Son of God, King of Israel',
 'Nathanael answered "Rabbi, you are the Son of God! You are the King of Israel!" (John 1:49).'),

-- Stage 3: Medium
(43,1,3,'John 1 says the world was made through the Word. How did the world respond?',
 '["It did not know him","It worshiped him","It feared him","It rejected him with violence"]','It did not know him',
 '"He was in the world… yet the world did not know him" (John 1:10).'),
(43,1,3,'In John 1, the Word came to "his own." What was their response?',
 '["His own people did not receive him","His own people welcomed him","His own people worshiped him","His own people were afraid"]','His own people did not receive him',
 '"He came to his own, and his own people did not receive him" (John 1:11).'),
(43,1,3,'How does John 1:13 describe those who became children of God?',
 '["Born not of blood, nor of the will of the flesh, nor of the will of man, but of God","Born of the Spirit alone","Born of their own faith","Born through the apostles'' teaching"]','Born not of blood, nor of the will of the flesh, nor of the will of man, but of God',
 'John 1:13 describes spiritual rebirth as entirely from God, not human effort.'),
(43,1,3,'John 1:16 says "from his fullness we have all received grace upon grace." What does this phrase suggest?',
 '["Abundant, overflowing grace","A single act of grace","Grace equal to our sin","Grace earned by works"]','Abundant, overflowing grace',
 '"Grace upon grace" (or "grace for grace") suggests an inexhaustible supply of grace.'),
(43,1,3,'In John 1, who among the disciples was "with Jesus and stayed with him" first?',
 '["Andrew and another unnamed disciple","Peter and John","Philip and Nathanael","James and Thomas"]','Andrew and another unnamed disciple',
 'Andrew and an unnamed disciple (likely the author John) first followed Jesus (John 1:35–40).'),

-- Stage 4: Hard
(43,1,4,'John 1 says John came as a witness to the light "so that all might believe through him." Why does John clarify that John was NOT the light?',
 '["To prevent people from mistaking John for the Messiah","Because John sinned","Because John came before creation","Because John was afraid"]','To prevent people from mistaking John for the Messiah',
 'John 1:8 clarifies the Baptist''s role: he was a witness, not the light itself.'),
(43,1,4,'John 1:3 states "without him was not any thing made that was made." How does this relate to the claim that the Word was God?',
 '["It affirms the Word''s divine creative power, supporting his deity","It means the Word was a lesser deity","It only applies to earthly things","It contradicts the creation account in Genesis"]','It affirms the Word''s divine creative power, supporting his deity',
 'Universal creative agency belongs only to God; the Word being the agent of all creation confirms his deity.'),
(43,1,4,'The Pharisees questioned John about his identity and baptizing. What right did they imply was needed to baptize?',
 '["Being the Christ, Elijah, or the Prophet","Being a Levite","Having a temple commission","Being sent by the Sanhedrin"]','Being the Christ, Elijah, or the Prophet',
 'They asked "Why then are you baptizing, if you are neither the Christ, nor Elijah, nor the Prophet?" (John 1:25).'),
(43,1,4,'In what way does Nathanael''s confession ("Son of God… King of Israel") connect with the rest of John''s Gospel?',
 '["It previews the two main titles John uses for Jesus throughout","It was just politeness","It was quickly retracted","It referred only to Jesus'' earthly kingship"]','It previews the two main titles John uses for Jesus throughout',
 'John''s Gospel builds toward these two titles: divine Son and royal Messiah.'),
(43,1,4,'Jesus'' statement to Nathanael about "angels ascending and descending on the Son of Man" echoes which Old Testament event?',
 '["Jacob''s ladder at Bethel","Moses at the burning bush","Elijah''s chariot of fire","Isaiah''s vision of the throne"]','Jacob''s ladder at Bethel',
 'Genesis 28:12 describes angels ascending and descending; Jesus identifies himself as the new "Bethel" (house of God).'),

-- Stage 5: Very Hard
(43,1,5,'The phrase "the Word was with God" uses the Greek preposition pros. What nuance does this add beyond mere coexistence?',
 '["Intimate face-to-face relationship, not just spatial proximity","Physical location in heaven","Equality of power","Temporal sequence"]','Intimate face-to-face relationship, not just spatial proximity',
 'Pros implies a dynamic, face-to-face relationship, communicating the deep relational intimacy within the Trinity.'),
(43,1,5,'John 1:18 says "No one has ever seen God; the only God, who is at the Father''s side, he has made him known." How does this verse summarize John''s Prologue?',
 '["The incarnate Word uniquely reveals the invisible God to humanity","God is unknowable","Only John the Baptist has seen God","This is about OT prophets"]','The incarnate Word uniquely reveals the invisible God to humanity',
 'The Prologue''s purpose is to show that the eternal Word became flesh precisely to make the unseen God known.'),
(43,1,5,'Grace and truth in John 1:14,17 echo the Hebrew pair hesed and emet. Why is this significant?',
 '["It ties Jesus to the covenant character of God revealed to Moses, showing he fulfills the OT revelation","It is a Greek philosophical concept only","It means Jesus replaces the OT entirely","It refers only to gentile audiences"]','It ties Jesus to the covenant character of God revealed to Moses, showing he fulfills the OT revelation',
 'Hesed (steadfast love/grace) and emet (faithfulness/truth) describe YHWH''s character in Exodus 34:6; Jesus embodies the same.'),
(43,1,5,'How does the structure of John 1:1 ("In the beginning was the Word") deliberately echo Genesis 1:1?',
 '["Both open with the same phrase, presenting Jesus as the agent of the new creation, parallel to the first creation","It is a coincidence","John is quoting Genesis to show the law is superseded","It only shows Jesus pre-existed Abraham"]','Both open with the same phrase, presenting Jesus as the agent of the new creation, parallel to the first creation',
 'John intentionally mirrors Genesis 1:1 to present the ministry of Jesus as a new creation story.'),
(43,1,5,'What is the theological significance of John saying "we have beheld his glory" (v.14) using the first person plural?',
 '["It grounds the Prologue''s theology in eyewitness testimony, giving historical credibility to the claims","It refers to the angels","It means all humanity saw","It contradicts the claim no one has seen God"]','It grounds the Prologue''s theology in eyewitness testimony, giving historical credibility to the claims',
 'The "we" signals the apostolic community''s direct experience, tying the lofty Prologue to real historical witness.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- JOHN 2
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(43,2,1,'At what event did Jesus perform his first miracle in John 2?',
 '["A wedding in Cana","A feast in Jerusalem","A synagogue in Nazareth","A gathering in Capernaum"]','A wedding in Cana',
 'The first sign was at a wedding in Cana of Galilee (John 2:1).'),
(43,2,1,'What problem arose at the wedding in Cana?',
 '["They ran out of wine","The guests stopped coming","The food was gone","A storm arose"]','They ran out of wine',
 'Mary told Jesus "They have no wine" (John 2:3).'),
(43,2,1,'What did Jesus turn water into at the wedding?',
 '["Wine","Bread","Oil","Healing water"]','Wine',
 'Jesus turned the water into wine (John 2:9).'),
(43,2,1,'How many stone water jars were filled at the wedding in Cana?',
 '["Six","Three","Seven","Twelve"]','Six',
 '"Now there were six stone water jars there…" (John 2:6).'),
(43,2,1,'What did Jesus do in the temple that shocked everyone?',
 '["He drove out the money changers and those selling animals","He healed many people","He preached for hours","He refused to pay the temple tax"]','He drove out the money changers and those selling animals',
 'Jesus made a whip and drove out those selling animals, and overturned the money changers'' tables (John 2:14–15).'),
(43,2,1,'What did Jesus say about his body in John 2:19?',
 '["Destroy this temple, and in three days I will raise it up","My body is the bread of life","My flesh is given for the world","I am the living temple"]','Destroy this temple, and in three days I will raise it up',
 'John 2:19 records Jesus saying "Destroy this temple, and in three days I will raise it up."'),
(43,2,1,'Who told Jesus at the wedding "They have no wine"?',
 '["His mother Mary","A servant","A disciple","The master of the feast"]','His mother Mary',
 'Mary brought the problem to Jesus (John 2:3).'),
(43,2,1,'What did the master of the feast notice about the good wine at Cana?',
 '["It was saved until last, unlike custom","It was brought from far away","It had been blessed by a rabbi","It appeared from thin air"]','It was saved until last, unlike custom',
 'He said "You have kept the good wine until now" (John 2:10), noting the reversal of the usual custom.'),
(43,2,1,'After the temple cleansing, what sign did the Jews ask Jesus to show to prove his authority?',
 '["A sign","His credentials","A miracle from God","His lineage"]','A sign',
 '"What sign do you show us for doing these things?" (John 2:18).'),
(43,2,1,'After the resurrection, what did the disciples remember about the temple incident?',
 '["They remembered Jesus''s words and believed the Scripture","They were still confused","They asked Jesus to explain","They forgot it entirely"]','They remembered Jesus''s words and believed the Scripture',
 'John 2:22 says after he was raised they "remembered… and they believed the Scripture."'),

-- Stage 2
(43,2,2,'What does John call the miracle at Cana?',
 '["The first of his signs","A wonder","A proof","A great work"]','The first of his signs',
 '"This, the first of his signs, Jesus did at Cana in Galilee" (John 2:11).'),
(43,2,2,'What was the result of the first sign at Cana on the disciples?',
 '["They believed in him","They were afraid","They questioned him","They told no one"]','They believed in him',
 '"His disciples believed in him" (John 2:11).'),
(43,2,2,'How much water did the six stone jars hold in total?',
 '["120–180 gallons (20–30 each)","30 gallons total","A few cups each","An unknown amount"]','120–180 gallons (20–30 each)',
 'Each jar held 20–30 gallons; six jars = 120–180 gallons of wine.'),
(43,2,2,'Why did the Jews think it was impossible for Jesus to rebuild the temple in three days?',
 '["It took 46 years to build","It was God''s house","The Romans controlled it","The priests would not allow it"]','It took 46 years to build',
 '"It has taken forty-six years to build this temple" (John 2:20).'),
(43,2,2,'In John 2:21, what temple was Jesus actually talking about?',
 '["The temple of his body","The Jerusalem temple","A heavenly temple","A metaphorical temple"]','The temple of his body',
 '"He was speaking about the temple of his body" (John 2:21).'),
(43,2,2,'What did Jesus say when he responded to his mother at the wedding?',
 '["Woman, what does this have to do with me? My hour has not yet come.","Do not worry, I will help.","Let me pray first.","This is not the right time or place."]','Woman, what does this have to do with me? My hour has not yet come.',
 'John 2:4 records Jesus''s initial response to Mary.'),
(43,2,2,'After the Passover feast, why didn''t Jesus entrust himself to those who believed in him?',
 '["He knew all people and did not need their testimony about man","He was testing their faith","He was still teaching them","The Pharisees were watching"]','He knew all people and did not need their testimony about man',
 '"He knew all people… he himself knew what was in man" (John 2:24–25).'),
(43,2,2,'Who told the servants at the wedding "Do whatever he tells you"?',
 '["Mary","The master of the feast","A disciple","Jesus himself"]','Mary',
 'Mary told the servants "Do whatever he tells you" (John 2:5).'),
(43,2,2,'Why was Jesus angry at the temple sellers and money changers?',
 '["They had turned his Father''s house into a house of trade","They were cheating people","They were working on the Sabbath","They refused to pay taxes"]','They had turned his Father''s house into a house of trade',
 '"Stop making my Father''s house a house of trade" (John 2:16).'),
(43,2,2,'When was the Passover feast that Jesus attended in John 2?',
 '["At the start of his ministry (first Passover in John)","At the end of his ministry","After the resurrection","Before his baptism"]','At the start of his ministry (first Passover in John)',
 'This Passover in John 2 is the first of three Passovers in John''s Gospel.'),

-- Stage 3
(43,2,3,'What is the theological significance of the "hour" Jesus mentions in John 2:4?',
 '["It refers to his coming death and glorification, a theme throughout John","It just means he is busy","It refers to the Sabbath","It means the wedding feast was over"]','It refers to his coming death and glorification, a theme throughout John',
 'In John, "the hour" consistently refers to the passion and glorification of Jesus (cf. 7:30; 12:23; 17:1).'),
(43,2,3,'How does the abundance of wine at Cana (120–180 gallons) serve as a sign pointing to Jesus''s identity?',
 '["It demonstrates the lavish provision of the messianic age prophesied in Amos 9:13–14","It was just a practical solution","It showed Jesus was a good guest","It was meant to embarrass the host"]','It demonstrates the lavish provision of the messianic age prophesied in Amos 9:13–14',
 'OT prophets linked wine abundance with the coming kingdom; Jesus''s sign signals the arrival of the new age.'),
(43,2,3,'What does the stone water jars being used for "Jewish rites of purification" add to the meaning of Jesus''s miracle?',
 '["Jesus transforms the old purification system into the new wine of the gospel","It is just a practical detail","The jars were the only containers available","It shows Jesus respected Jewish law"]','Jesus transforms the old purification system into the new wine of the gospel',
 'The replacement of purification water with wine signals that Jesus brings a new and better covenant.'),
(43,2,3,'Many believed in Jesus at the Passover feast in Jerusalem "when they saw the signs he was doing." Why did Jesus NOT trust himself to them?',
 '["Their belief was based only on signs, not a deeper understanding","They were Pharisees","He was testing them","He had not yet taught enough"]','Their belief was based only on signs, not a deeper understanding',
 'John distinguishes between true saving faith and a superficial belief based merely on miracles (cf. John 6:14–15, 26).'),
(43,2,3,'What connection does the disciples'' later remembrance (John 2:22) show about John''s Gospel?',
 '["The resurrection gives them interpretive perspective to understand Jesus''s earlier words","They had poor memories","John wrote this before the resurrection","Jesus explained it to them later"]','The resurrection gives them interpretive perspective to understand Jesus''s earlier words',
 'Post-resurrection understanding is a key theme in John; the Spirit of truth leads them into all truth (John 16:13).'),

-- Stage 4
(43,2,4,'How does John''s placement of the temple cleansing (early in Jesus''s ministry) differ from the Synoptic Gospels?',
 '["The Synoptics place it at the end; this may be a different event or John has a theological rather than strict chronological arrangement","John and the Synoptics are contradictory","The Synoptics never mention the temple cleansing","Both place it at Passover before the crucifixion"]','The Synoptics place it at the end; this may be a different event or John has a theological rather than strict chronological arrangement',
 'This is a classic synoptic problem; scholars debate whether there were two cleansings or John rearranged events thematically.'),
(43,2,4,'Zeal for God''s house will consume me (John 2:17) is a quote from which Psalm?',
 '["Psalm 69","Psalm 22","Psalm 118","Psalm 2"]','Psalm 69',
 'John 2:17 quotes Psalm 69:9, connecting Jesus''s action to the suffering servant''s zeal.'),
(43,2,4,'The disciples connected the temple saying to Psalm 69:9. What does this retrospective interpretation suggest?',
 '["OT Scripture shaped how the disciples understood and narrated Jesus''s actions","They were confused at the time","This was added later without connection to events","The disciples had memorized all the Psalms"]','OT Scripture shaped how the disciples understood and narrated Jesus''s actions',
 'John frequently shows the disciples understanding events through OT fulfillment after the resurrection.'),
(43,2,4,'How does the wedding at Cana and the temple cleansing together function as an opening statement in John?',
 '["Together they present Jesus as the one who transforms old institutions (purification, temple) and brings the new wine of the messianic age","They are unrelated stories","They both took place in Jerusalem","They both show Jesus''s power over nature"]','Together they present Jesus as the one who transforms old institutions (purification, temple) and brings the new wine of the messianic age',
 'These opening signs bracket the first week of Jesus''s ministry as a programmatic statement about new covenant transformation.'),

-- Stage 5
(43,2,5,'John 2:11 says the sign "manifested his glory." How does this connect the Cana miracle to the Prologue (John 1:14)?',
 '["The Prologue says we beheld his glory; the signs are the narrative demonstration of that glory","It is a literary accident","Glory here means fame, not divine glory","This is only about Old Testament glory"]','The Prologue says we beheld his glory; the signs are the narrative demonstration of that glory',
 'John 1:14 announces the divine glory; chapters 2–12 ("Book of Signs") show that glory through the seven signs.'),
(43,2,5,'If Jesus''s body is the true temple (2:21), what are the implications for post-resurrection worship according to John''s theology?',
 '["Access to God is now through the risen Christ, not a physical building; worship is in spirit and truth (cf. 4:21–24)","Physical temples are still necessary","This only applies to Jewish Christians","The resurrection ended all worship"]','Access to God is now through the risen Christ, not a physical building; worship is in spirit and truth (cf. 4:21–24)',
 'The replacement of the temple by Jesus''s body points forward to worship "in spirit and truth" (John 4:23–24).'),
(43,2,5,'Why is "they believed the Scripture and the word that Jesus had spoken" (2:22) theologically significant for John''s view of revelation?',
 '["It places Scripture and Jesus''s words on the same level of divine authority","It suggests Scripture is above Jesus","It means they only trusted Moses","It was just an emotional response"]','It places Scripture and Jesus words on the same level of divine authority',
 'John''s Gospel regularly equates Jesus''s words with Scripture, presenting both as vehicles of divine truth.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- JOHN 3
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(43,3,1,'Who came to Jesus by night in John 3?',
 '["Nicodemus","Joseph of Arimathea","The Rich Young Ruler","Zacchaeus"]','Nicodemus',
 'Nicodemus, a Pharisee and ruler of the Jews, came to Jesus at night (John 3:1–2).'),
(43,3,1,'What title did Nicodemus use when he addressed Jesus?',
 '["Rabbi (Teacher)","Lord","Master","Prophet"]','Rabbi (Teacher)',
 '"Rabbi, we know that you are a teacher come from God" (John 3:2).'),
(43,3,1,'What did Jesus say a person must do to see the kingdom of God?',
 '["Be born again (born from above)","Keep the commandments","Be baptized by John","Sell everything"]','Be born again (born from above)',
 '"Unless one is born again he cannot see the kingdom of God" (John 3:3).'),
(43,3,1,'What is John 3:16 about?',
 '["God''s love for the world and salvation through believing in Jesus","The creation of the world","The coming judgment","Jesus''s command to love one another"]','God''s love for the world and salvation through believing in Jesus',
 '"For God so loved the world, that he gave his only Son, that whoever believes in him should not perish but have eternal life."'),
(43,3,1,'What does John 3:16 say God gave for the world?',
 '["His only Son","The Holy Spirit","The Law","The Scriptures"]','His only Son',
 '"He gave his only Son."'),
(43,3,1,'In John 3, what did John the Baptist say about Jesus compared to himself?',
 '["He must increase, but I must decrease","He is greater in rank only","We are equal messengers","I will follow him"]','He must increase, but I must decrease',
 '"He must increase, but I must decrease" (John 3:30).'),
(43,3,1,'What must a person be born of to enter the kingdom of God, according to John 3:5?',
 '["Water and the Spirit","Faith and works","Repentance and baptism","Obedience and prayer"]','Water and the Spirit',
 '"Unless one is born of water and the Spirit, he cannot enter the kingdom of God" (John 3:5).'),
(43,3,1,'What Old Testament event did Jesus use as a picture of himself being "lifted up"?',
 '["Moses lifting up the serpent in the wilderness","Elijah going up to heaven","Jacob''s ladder","Isaac on the altar"]','Moses lifting up the serpent in the wilderness',
 '"As Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up" (John 3:14).'),
(43,3,1,'What did Jesus say about those who believe in the Son in John 3:36?',
 '["They have eternal life","They will be blessed","They will see God","They will never sin"]','They have eternal life',
 '"Whoever believes in the Son has eternal life" (John 3:36).'),
(43,3,1,'What was Nicodemus''s role among the Jews?',
 '["A ruler and Pharisee","A tax collector","A Levite priest","A Roman official"]','A ruler and Pharisee',
 'Nicodemus was "a ruler of the Jews" and a Pharisee (John 3:1).'),

-- Stage 2
(43,3,2,'What was Nicodemus''s confused response when Jesus said he must be born again?',
 '["Can a man enter his mother''s womb a second time?","How can a spirit enter a new body?","What does ''again'' mean?","Is this a spiritual teaching?"]','Can a man enter his mother''s womb a second time?',
 '"Can a man enter his mother''s womb a second time and be born?" (John 3:4).'),
(43,3,2,'Jesus described being born of the Spirit as being like what?',
 '["The wind—you hear it but don''t know where it comes from or goes","A fire that purifies","A river of living water","A dove descending"]','The wind—you hear it but don''t know where it comes from or goes',
 '"The wind blows where it wishes… so it is with everyone who is born of the Spirit" (John 3:8).'),
(43,3,2,'What does John 3:17 say was God''s purpose in sending his Son into the world?',
 '["Not to condemn, but to save the world","To judge all nations","To fulfill the law","To replace the Old Testament"]','Not to condemn, but to save the world',
 '"God did not send his Son into the world to condemn the world, but in order that the world might be saved through him" (John 3:17).'),
(43,3,2,'What does John 3:19 say is the reason for condemnation?',
 '["Light has come into the world, but people loved darkness rather than light","People broke the law","People rejected the prophets","People were born sinful"]','Light has come into the world, but people loved darkness rather than light',
 '"This is the judgment: the light has come into the world, and people loved the darkness rather than the light" (John 3:19).'),
(43,3,2,'What does John 3:18 say about one who believes in Jesus?',
 '["He is not condemned","He is forgiven of all past sins","He gains eternal happiness","He becomes a child of God"]','He is not condemned',
 '"Whoever believes in him is not condemned" (John 3:18).'),
(43,3,2,'Jesus called Nicodemus "the teacher of Israel." Why was Nicodemus surprised by Jesus''s teaching?',
 '["He did not understand spiritual birth despite being a religious teacher","He was too old to learn","He had never read the Scriptures","He thought Jesus was a fraud"]','He did not understand spiritual birth despite being a religious teacher',
 'Jesus said "Are you the teacher of Israel and yet you do not understand these things?" (John 3:10).'),
(43,3,2,'In John 3, what did John the Baptist say about himself being the bridegroom?',
 '["He was the friend of the bridegroom, not the bridegroom himself","He was the best man","He was the one who prepared the bride","He refused the title"]','He was the friend of the bridegroom, not the bridegroom himself',
 '"The friend of the bridegroom… rejoices greatly at the bridegroom''s voice" (John 3:29).'),
(43,3,2,'According to John 3:33, what does receiving Jesus''s testimony testify?',
 '["That God is true","That Jesus is Messiah","That eternal life exists","That sin is forgiven"]','That God is true',
 '"Whoever receives his testimony sets his seal to this, that God is true" (John 3:33).'),
(43,3,2,'In John 3:36, what is the fate of one who does not obey the Son?',
 '["The wrath of God remains on him","He is given a second chance","He is ignored","He returns to death"]','The wrath of God remains on him',
 '"Whoever does not obey the Son shall not see life, but the wrath of God remains on him" (John 3:36).'),
(43,3,2,'What does John 3:34 say about the Spirit given to Jesus?',
 '["God gives the Spirit without measure","The Spirit was given in fullness only at Pentecost","Only prophets receive the Spirit","The Spirit was limited by law"]','God gives the Spirit without measure',
 '"He whom God has sent utters the words of God, for he gives the Spirit without measure" (John 3:34).'),

-- Stage 3
(43,3,3,'Why did Nicodemus come to Jesus at night, and what might this detail symbolize in John''s Gospel?',
 '["Night symbolizes spiritual darkness/uncertainty; Nicodemus is moving from darkness toward the light","It was just more convenient","Night means he was afraid of crowds only","It has no symbolic meaning"]','Night symbolizes spiritual darkness/uncertainty; Nicodemus is moving from darkness toward the light',
 'John uses light/darkness as a major theme (1:5; 8:12; 9:4); Nicodemus at night fits the pattern of one not yet in the light.'),
(43,3,3,'How does John 3:14-15 tie the crucifixion to the bronze serpent in Numbers 21?',
 '["Both involve being lifted up to bring life to those who look/believe; sin''s judgment is borne so others may live","It is just a casual comparison","The serpent was a symbol of Satan","Jesus quoted it to confuse Nicodemus"]','Both involve being lifted up to bring life to those who look/believe; sin''s judgment is borne so others may live',
 'In Numbers 21 the serpent bore the curse so Israelites who looked lived; Jesus bore sin''s curse so believers live.'),
(43,3,3,'What is the meaning of "born from above" (anothen) and why is it significant that Nicodemus misunderstood it?',
 '["Anothen means both ''again'' and ''from above''; Nicodemus took the physical meaning while Jesus meant divine origin","It only means ''again'' in Aramaic","Nicodemus understood perfectly","It is a translation issue with no theological weight"]','Anothen means both again and from above; Nicodemus took the physical meaning while Jesus meant divine origin',
 'The Greek double meaning drives the dialogue; Jesus means a birth from God, not a second physical birth.'),
(43,3,3,'How does John 3:16 function as a summary of John''s Gospel?',
 '["It encapsulates the themes of God''s love, the gift of the Son, belief, and eternal life that run through the whole Gospel","It is an isolated verse with no connection to the rest","It is a quotation from the Old Testament","It only applies to Jewish readers"]','It encapsulates the themes of God''s love, the gift of the Son, belief, and eternal life that run through the whole Gospel',
 'Scholars identify John 3:16 as the Gospel''s thesis statement: love → gift → faith → life.'),
(43,3,3,'Why does John the Baptist''s joy at Jesus''s growing ministry (3:29–30) mark spiritual maturity?',
 '["It shows he found his identity in being a witness, not in his own prominence; true joy in another''s success","He was just being polite","He was disappointed but hiding it","He was preparing to retire"]','It shows he found his identity in being a witness, not in his own prominence; true joy in another''s success',
 '"He must increase, but I must decrease" expresses complete self-giving to the mission, not self-promotion.'),

-- Stage 4
(43,3,4,'How do John 3:16 and John 3:36 together present the two sides of the gospel?',
 '["Belief brings eternal life (positive); unbelief leaves God''s wrath (negative) — both grace and judgment are real","They are contradictory","3:16 is for Jews and 3:36 is for gentiles","3:36 cancels 3:16"]','Belief brings eternal life (positive); unbelief leaves God s wrath (negative) — both grace and judgment are real',
 'John presents the gospel as a two-edged reality: the offer of life and the reality of judgment.'),
(43,3,4,'John 3:5 says born of "water and Spirit." What are the main interpretations of "water" here?',
 '["Physical birth (amniotic water), baptism, or cleansing/renewal — all point to the need for divine renewal","Water only means baptism","Water means the Jordan River","Water refers to the Old Testament law"]','Physical birth (amniotic water), baptism, or cleansing/renewal — all point to the need for divine renewal',
 'Scholars debate: some see water as baptism, others as physical birth, others as OT cleansing imagery (Ezek. 36:25–27).'),
(43,3,4,'What echoes of Ezekiel 36:25–27 appear in Jesus''s conversation with Nicodemus?',
 '["God promised to sprinkle clean water and put a new spirit within Israel; Jesus speaks of water and Spirit birth","None; it is purely from the Psalms","Only the Spirit part connects to Ezekiel","Ezekiel spoke of a new temple, not birth"]','God promised to sprinkle clean water and put a new spirit within Israel; Jesus speaks of water and Spirit birth',
 'Ezek. 36:25–27 is the OT backdrop: God cleanses with water and gives his Spirit — exactly what Jesus describes.'),
(43,3,4,'John 3:13 says "No one has ascended into heaven except he who descended from heaven." How does this challenge Jewish ideas of access to God?',
 '["It claims that only the incarnate Son has the authority to reveal heavenly things, since he alone has been there","It only refers to angels","It means humans cannot pray to God","It contradicts Moses''s ascent to Sinai"]','It claims that only the incarnate Son has the authority to reveal heavenly things, since he alone has been there',
 'The claim is exclusive: the Son alone bridges heaven and earth and can speak authoritatively of heavenly realities.'),

-- Stage 5
(43,3,5,'What does "monogenes" (only Son/only begotten) in John 3:16 convey about the Son''s relationship to the Father?',
 '["Unique, one-of-a-kind divine Son — not merely a created being, but the one uniquely sharing the Father''s nature","Simply that Jesus was God''s first creation","That Jesus had no siblings","A title of affection without ontological weight"]','Unique, one-of-a-kind divine Son — not merely a created being, but the one uniquely sharing the Father''s nature',
 'Monogenes (from monos + genos) means uniquely begotten/one of a kind, affirming Jesus''s unique divine Sonship.'),
(43,3,5,'How does Nicodemus''s arc across John''s Gospel (ch. 3, 7, 19) illustrate the Gospel''s theme of moving from darkness to light?',
 '["He begins in secret nighttime inquiry, defends Jesus mildly in ch. 7, and boldly buries Jesus in ch. 19 — growing in public identification","He never changes","He abandons Jesus by ch. 19","He becomes a disciple immediately in ch. 3"]','He begins in secret nighttime inquiry, defends Jesus mildly in ch. 7, and boldly buries Jesus in ch. 19 — growing in public identification',
 'Nicodemus''s three appearances trace a journey from cautious secrecy to costly public loyalty — a movement toward light.'),
(43,3,5,'John 3:19 says people "loved darkness rather than light." How does this relate to John''s doctrine of human moral responsibility?',
 '["It establishes that condemnation is not arbitrary but based on a willful moral choice to reject revealed light","It means God predestines some to darkness","It only describes a few wicked people","It is a statement about cultural darkness"]','It establishes that condemnation is not arbitrary but based on a willful moral choice to reject revealed light',
 'John insists judgment is self-incurred: people choose darkness; they are not randomly condemned. This upholds both sovereignty and responsibility.'),
(43,3,5,'How does John 3:16 fit within John''s broader Christology where the Father sends the Son?',
 '["The mission of the Son is grounded in the Father''s love; the sending pattern (3:17; 5:24; 6:44; 17:3) defines Jesus''s identity as the sent one","The Father and Son are separate beings acting independently","Sending implies the Son is inferior","This sending language is found only in John 3"]','The mission of the Son is grounded in the Father''s love; the sending pattern defines Jesus''s identity as the sent one',
 '"Sending" Christology is central to John: the Father-Son relationship of love drives the entire incarnation and redemptive mission.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- MARK 1
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(41,1,1,'How does Mark begin his Gospel?',
 '["The beginning of the gospel of Jesus Christ, the Son of God","In the beginning was the Word","The book of the genealogy of Jesus Christ","I, Mark, a servant of Jesus Christ"]','The beginning of the gospel of Jesus Christ, the Son of God',
 'Mark 1:1 opens "The beginning of the gospel of Jesus Christ, the Son of God."'),
(41,1,1,'Who baptized Jesus in Mark 1?',
 '["John the Baptist","Peter","Elijah","The Holy Spirit"]','John the Baptist',
 'John the Baptist baptized Jesus in the Jordan River (Mark 1:9).'),
(41,1,1,'What happened when Jesus came up out of the water after his baptism?',
 '["The heavens were torn open and the Spirit descended like a dove","An angel appeared","A cloud covered the sky","He immediately began preaching"]','The heavens were torn open and the Spirit descended like a dove',
 '"Immediately… he saw the heavens being torn open and the Spirit descending on him like a dove" (Mark 1:10).'),
(41,1,1,'What did the voice from heaven say at Jesus''s baptism?',
 '["You are my beloved Son; with you I am well pleased","This is my servant whom I have chosen","Rise and be holy","Go and preach the gospel"]','You are my beloved Son; with you I am well pleased',
 '"A voice came from heaven, You are my beloved Son; with you I am well pleased" (Mark 1:11).'),
(41,1,1,'How long was Jesus in the wilderness being tempted by Satan?',
 '["40 days","3 days","7 days","1 year"]','40 days',
 'Jesus was in the wilderness 40 days being tempted by Satan (Mark 1:13).'),
(41,1,1,'What were Simon and Andrew doing when Jesus called them?',
 '["Casting a net into the sea","Repairing their nets","Sitting in a boat","Fishing with James and John"]','Casting a net into the sea',
 '"Immediately he saw Simon and Andrew his brother casting a net into the sea" (Mark 1:16).'),
(41,1,1,'What did Jesus say to Simon and Andrew when he called them?',
 '["Follow me, and I will make you become fishers of men","Come and see where I live","Repent, for the kingdom is near","Leave your boats and follow God"]','Follow me, and I will make you become fishers of men',
 '"Follow me, and I will make you become fishers of men" (Mark 1:17).'),
(41,1,1,'Who did Jesus heal in the synagogue in Mark 1?',
 '["A man with an unclean spirit","A blind man","A lame man","A deaf-mute"]','A man with an unclean spirit',
 'In the synagogue at Capernaum, Jesus healed a man with an unclean spirit (Mark 1:23–26).'),
(41,1,1,'Whose mother-in-law did Jesus heal in Mark 1?',
 '["Simon Peter''s","Andrew''s","James''s","John''s"]','Simon Peter''s',
 'Jesus healed Simon''s mother-in-law who had a fever (Mark 1:30–31).'),
(41,1,1,'What did Jesus do early in the morning after a busy day of ministry?',
 '["He went to a desolate place to pray","He preached to the crowds","He taught in the synagogue","He rested with the disciples"]','He went to a desolate place to pray',
 '"And rising very early in the morning… he went out to a desolate place, and there he prayed" (Mark 1:35).'),

-- Stage 2
(41,1,2,'What was John the Baptist''s message?',
 '["A baptism of repentance for the forgiveness of sins","Prepare for war against Rome","Give to the poor","The law of Moses is fulfilled"]','A baptism of repentance for the forgiveness of sins',
 '"John appeared, baptizing in the wilderness and proclaiming a baptism of repentance for the forgiveness of sins" (Mark 1:4).'),
(41,1,2,'What did John say about the one coming after him?',
 '["He is mightier than I; I am not worthy to stoop down and untie his sandals","He will judge all nations","He will baptize with water","He is my equal"]','He is mightier than I; I am not worthy to stoop down and untie his sandals',
 'Mark 1:7: "After me comes he who is mightier than I, the strap of whose sandals I am not worthy to stoop down and untie."'),
(41,1,2,'What did John say the one coming after him would baptize with?',
 '["The Holy Spirit","Water and fire","Blood","The Spirit and truth"]','The Holy Spirit',
 '"He will baptize you with the Holy Spirit" (Mark 1:8).'),
(41,1,2,'What was Jesus''s summary message when he began preaching in Galilee?',
 '["The time is fulfilled, and the kingdom of God is at hand; repent and believe in the gospel","Love God and love your neighbor","Follow the law of Moses","Blessed are the poor in spirit"]','The time is fulfilled, and the kingdom of God is at hand; repent and believe in the gospel',
 '"The time is fulfilled, and the kingdom of God is at hand; repent and believe in the gospel" (Mark 1:15).'),
(41,1,2,'What did the unclean spirit say to Jesus in the synagogue?',
 '["What have you to do with us, Jesus of Nazareth? Have you come to destroy us? I know who you are—the Holy One of God","Leave us alone!","We know you are the Messiah","Do not torment us before the time"]','What have you to do with us, Jesus of Nazareth? Have you come to destroy us? I know who you are—the Holy One of God',
 'The spirit recognized Jesus''s identity and authority (Mark 1:24).'),
(41,1,2,'What did the people say after Jesus healed the man with an unclean spirit?',
 '["What is this? A new teaching with authority!","He is the Messiah!","This is witchcraft!","We have never seen anything like this!"]','What is this? A new teaching with authority!',
 '"What is this? A new teaching with authority! He commands even the unclean spirits, and they obey him" (Mark 1:27).'),
(41,1,2,'After Jesus healed Simon''s mother-in-law, what did she do?',
 '["She served them","She worshiped Jesus","She told the town","She went back to sleep"]','She served them',
 '"She began to serve them" (Mark 1:31).'),
(41,1,2,'In Mark 1, Jesus healed a man with leprosy. What did Jesus do before healing him?',
 '["He was moved with pity and touched him","He prayed for him first","He spoke from a distance","He asked him about his sins"]','He was moved with pity and touched him',
 '"Moved with pity, he stretched out his hand and touched him" (Mark 1:41).'),
(41,1,2,'What instructions did Jesus give the healed leper?',
 '["Go show yourself to the priest and offer what Moses commanded; tell no one","Go and tell everyone","Come back tomorrow","Give thanks publicly in the synagogue"]','Go show yourself to the priest and offer what Moses commanded; tell no one',
 '"See that you say nothing to anyone, but go, show yourself to the priest, and offer for your cleansing what Moses commanded" (Mark 1:44).'),
(41,1,2,'What happened when the leper spread the news instead of keeping quiet?',
 '["Jesus could no longer openly enter a town but stayed outside","The authorities arrested Jesus","Everyone repented","More crowds gathered to hear him teach"]','Jesus could no longer openly enter a town but stayed outside',
 '"Jesus could no longer openly enter a town, but was out in desolate places, and people were coming to him from every quarter" (Mark 1:45).'),

-- Stage 3
(41,1,3,'Mark 1:1 calls Jesus "the Son of God." How does this title function at the start of the Gospel?',
 '["It signals to the reader Jesus''s true identity before the human characters understand it — a key Markan device","It summarizes the disciples'' beliefs","It quotes Psalm 2 directly","It is simply a polite title in that culture"]','It signals to the reader Jesus''s true identity before the human characters understand it — a key Markan device',
 'Mark uses dramatic irony: the reader knows who Jesus is (1:1; 1:11) long before the disciples confess it (8:29).'),
(41,1,3,'What does the word "immediately" (euthys) tell us about Mark''s narrative style?',
 '["It creates urgency and rapid pacing, emphasizing the powerful breakthrough of God''s kingdom","It is only a Greek filler word","It shows Mark was writing in a hurry","It always signals a miracle"]','It creates urgency and rapid pacing, emphasizing the powerful breakthrough of God''s kingdom',
 'Euthys appears ~41 times in Mark, driving the action forward; the kingdom is bursting into history with force.'),
(41,1,3,'Why might Mark note that "wild animals" were with Jesus in the wilderness (1:13)?',
 '["It echoes the new Eden — the second Adam reigns over creation as God intended, and angels serve him","It was just a description of the landscape","It shows danger and testing","It means Satan used animals to tempt him"]','It echoes the new Eden — the second Adam reigns over creation as God intended, and angels serve him',
 'The wilderness + wild animals + angelic service echoes Isaiah 11:6–9 and Psalm 91:11–13 — the new Adam restoring creation order.'),
(41,1,3,'The crowd was astonished at Jesus''s teaching because "he taught as one who had authority, not as the scribes." What does this contrast reveal?',
 '["The scribes appealed to tradition and precedent; Jesus spoke on his own authority — a claim that implied divine commission","Jesus was just more charismatic","The scribes were all corrupt","Jesus had more education"]','The scribes appealed to tradition and precedent; Jesus spoke on his own authority — a claim that implied divine commission',
 '"I say to you" (not "thus says the Lord") reflects Jesus speaking with inherent authority — a stunning contrast to rabbinic method.'),
(41,1,3,'In Mark 1, Jesus heals many diseases and drives out demons at Simon''s house. What does his command of both physical and spiritual realms suggest?',
 '["That the kingdom of God has arrived in power, breaking the hold of both sickness and evil","That Jesus was a skilled physician","That demons cause all sickness","That miracles were expected of prophets"]','That the kingdom of God has arrived in power, breaking the hold of both sickness and evil',
 'Jesus''s comprehensive healing demonstrates that the kingdom of God has come to reverse all effects of the Fall.'),

-- Stage 4
(41,1,4,'Mark 1:2 quotes "I send my messenger before your face" from Malachi 3:1 and Isaiah 40:3. What is the theological claim being made?',
 '["Jesus is the LORD (YHWH) of those prophecies; John is the Elijah-like forerunner of God''s own coming","John is the Messiah the prophets predicted","Isaiah 40 only refers to the return from Babylon","This is a secondary fulfillment with no direct connection"]','Jesus is the LORD (YHWH) of those prophecies; John is the Elijah-like forerunner of God''s own coming',
 'In Malachi 3:1 the Lord comes to his temple; John prepares the way for Jesus = Jesus is YHWH arriving in person.'),
(41,1,4,'Why is it significant that the unclean spirit, not the disciples, first publicly identifies Jesus as "the Holy One of God"?',
 '["It is part of Mark''s Messianic Secret — supernatural beings know who Jesus is while humans remain blind","The disciples later agreed","The spirit was lying","It is just a dramatic scene"]','It is part of Mark''s Messianic Secret — supernatural beings know who Jesus is while humans remain blind',
 'Demons see through the flesh; people do not. This irony runs through Mark, where the wrong beings keep revealing the secret.'),
(41,1,4,'Touching the leper (1:41) was a violation of purity law. What does this act reveal about Jesus''s approach to holiness?',
 '["Jesus''s holiness is contagious — he does not become unclean by touching the unclean; he makes the unclean clean","Jesus was ignorant of the law","Purity laws were only symbolic","Jesus was testing the Pharisees"]','Jesus''s holiness is contagious — he does not become unclean by touching the unclean; he makes the unclean clean',
 'Unlike the OT purity system (defilement spreads outward), Jesus''s power spreads inward: holiness overcomes uncleanness.'),
(41,1,4,'What does Jesus''s early morning prayer (1:35) reveal about the relationship between his public ministry and his inner life?',
 '["His power and mission were sustained by intimate communion with the Father — ministry flowed from prayer","He was simply an example for disciples to follow","He prayed because he was tired","Prayer was a cultural obligation"]','His power and mission were sustained by intimate communion with the Father — ministry flowed from prayer',
 'Even after enormous success (1:32–34), Jesus withdrew to pray; his authority came from the Father, not his own power.'),

-- Stage 5
(41,1,5,'How does the opening of Mark 1 (baptism, temptation, calling disciples) structure itself as a new Exodus narrative?',
 '["Baptism through water (new Red Sea crossing), wilderness testing like Israel''s 40 years, then calling a new community — Jesus recapitulates and succeeds where Israel failed","It is only incidentally similar","The Exodus is only in Matthew","The wilderness lasted 40 days not 40 years so there is no connection"]','Baptism through water (new Red Sea crossing), wilderness testing like Israel''s 40 years, then calling a new community — Jesus recapitulates and succeeds where Israel failed',
 'Mark 1 is a compressed new Exodus: the Spirit''s descent parallels the pillar of cloud, the wilderness echoes Numbers, and the calling mirrors Sinai.'),
(41,1,5,'The baptism scene (1:10–11) echoes Genesis 1:2 and Isaiah 42:1. What portrait of Jesus emerges from these allusions?',
 '["Jesus as the new creation agent (Spirit hovering as at creation) and the Servant of the Lord (Isaiah''s beloved in whom God delights)","Jesus is compared to Moses only","These are coincidental verbal parallels","Only Genesis 1 is relevant here"]','Jesus as the new creation agent (Spirit hovering as at creation) and the Servant of the Lord (Isaiah''s beloved in whom God delights)',
 'The Spirit hovering echoes Gen. 1:2 (new creation); "beloved… well pleased" echoes Isa. 42:1 (Servant); both identities shape Mark''s Christology.'),
(41,1,5,'Mark''s Gospel never records Jesus delivering a long sermon (unlike Matthew''s Sermon on the Mount). What does this structural choice say about Mark''s theological emphasis?',
 '["Mark emphasizes the deeds of the kingdom — what Jesus does reveals who he is — over extended teaching; the gospel is enacted, not only proclaimed","Mark had less material available","Mark was written for an uneducated audience","Jesus gave no teaching in Mark"]','Mark emphasizes the deeds of the kingdom — what Jesus does reveals who he is — over extended teaching; the gospel is enacted, not only proclaimed',
 'Mark''s structure foregrounds the inbreaking kingdom through action; proclamation and deed are inseparable, but deed is the lens.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- GENESIS 1
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(1,1,1,'What are the first words of the Bible?',
 '["In the beginning, God created the heavens and the earth","God said Let there be light","The Lord formed man from the dust","In the beginning was the Word"]','In the beginning, God created the heavens and the earth',
 'Genesis 1:1 opens "In the beginning, God created the heavens and the earth."'),
(1,1,1,'What was the state of the earth before God began creating?',
 '["Without form and void, with darkness over the deep","A beautiful garden","Full of water and fish","Covered in mountains"]','Without form and void, with darkness over the deep',
 '"The earth was without form and void, and darkness was over the face of the deep" (Gen. 1:2).'),
(1,1,1,'What was the first thing God created by speaking?',
 '["Light","The sky","The sea","The plants"]','Light',
 '"God said, Let there be light, and there was light" (Gen. 1:3).'),
(1,1,1,'On which day did God create light?',
 '["Day 1","Day 2","Day 3","Day 4"]','Day 1',
 'God created light on the first day of creation (Gen. 1:3–5).'),
(1,1,1,'What did God create on Day 2?',
 '["The sky (expanse/firmament)","The sea and dry land","The sun and moon","Birds and fish"]','The sky (expanse/firmament)',
 'On Day 2, God made the expanse (sky/firmament) to separate the waters above from the waters below (Gen. 1:6–8).'),
(1,1,1,'On which day did God create humans?',
 '["Day 6","Day 5","Day 7","Day 3"]','Day 6',
 'Humans were created on Day 6, along with land animals (Gen. 1:24–31).'),
(1,1,1,'In whose image did God create human beings?',
 '["In God''s own image","In the image of the angels","In their own image","In the image of all creatures"]','In God''s own image',
 '"God created man in his own image, in the image of God he created him" (Gen. 1:27).'),
(1,1,1,'What did God do on the seventh day?',
 '["He rested","He created more animals","He spoke to Adam","He made the rivers"]','He rested',
 '"On the seventh day God finished his work… and he rested on the seventh day" (Gen. 2:2).'),
(1,1,1,'After creating each thing, what did God say about his work?',
 '["It was good","It was perfect","It was finished","It was pleasing"]','It was good',
 'God repeatedly declares his creation "good" throughout Genesis 1.'),
(1,1,1,'What food did God give humans to eat, according to Genesis 1:29?',
 '["Every plant yielding seed and every tree with seed in its fruit","Animals and fish","Manna from heaven","Whatever they found"]','Every plant yielding seed and every tree with seed in its fruit',
 '"I have given you every plant yielding seed… and every tree with seed in its fruit" (Gen. 1:29).'),

-- Stage 2
(1,1,2,'What was created on Day 3?',
 '["Dry land, seas, and vegetation","Sun, moon, and stars","Fish and birds","Light"]','Dry land, seas, and vegetation',
 'On Day 3, God gathered the waters, made dry land appear, and created plants (Gen. 1:9–13).'),
(1,1,2,'What was created on Day 4?',
 '["Sun, moon, and stars","Birds and fish","Land animals","Plants"]','Sun, moon, and stars',
 'On Day 4, God created the lights in the expanse of the heavens to rule the day and night (Gen. 1:14–19).'),
(1,1,2,'What was created on Day 5?',
 '["Birds and sea creatures","Land animals","Plants","The sky"]','Birds and sea creatures',
 'On Day 5, God created the great sea creatures and birds (Gen. 1:20–23).'),
(1,1,2,'What two purposes did God give the sun and moon (Day 4)?',
 '["To separate day from night and to mark seasons, days, and years","To provide warmth and light only","To rule over humans","To signal the Sabbath"]','To separate day from night and to mark seasons, days, and years',
 '"Let them be for signs and for seasons, and for days and years" (Gen. 1:14).'),
(1,1,2,'God blessed humans and told them to do what, according to Genesis 1:28?',
 '["Be fruitful, multiply, fill the earth, and have dominion over it","Build cities and temples","Rest every seventh day","Name every animal"]','Be fruitful, multiply, fill the earth, and have dominion over it',
 '"Be fruitful and multiply and fill the earth and subdue it, and have dominion…" (Gen. 1:28).'),
(1,1,2,'What does "image of God" (imago Dei) mean practically in Genesis 1?',
 '["Humans represent and rule on God''s behalf as his vice-regents","Humans look physically like God","Humans have divine knowledge","Humans are sinless like God"]','Humans represent and rule on God''s behalf as his vice-regents',
 'In the ancient Near East, a king''s image represented his authority; humans bear God''s image to exercise his rule over creation.'),
(1,1,2,'What does God see about everything he had made at the end of Day 6?',
 '["It was very good","It was good","It was finished","It was pleasing to him"]','It was very good',
 '"And God saw everything that he had made, and behold, it was very good" (Gen. 1:31).'),
(1,1,2,'In Genesis 1:2, the Spirit of God "was hovering" over the waters. What does this image suggest?',
 '["Active creative presence ready to bring order and life out of chaos","A bird literally hovering","The third Person was not yet active","The water was dangerous"]','Active creative presence ready to bring order and life out of chaos',
 'The Spirit''s hovering (like a bird over a nest) signals ready creative action — life and order about to emerge.'),
(1,1,2,'Genesis 1 uses the term bara (create). Why is this word significant?',
 '["It is only used of God''s action — humans do not bara; it suggests creation of something new and unique","It just means to make anything","It can apply to any craftsman","It implies creation from existing material"]','It is only used of God''s action — humans do not bara; it suggests creation of something new and unique',
 'Bara in the Hebrew Bible is always used with God as subject, implying divine creative power distinct from human making.'),
(1,1,2,'How does the creation of humans as "male and female" (Gen. 1:27) fit within the image of God?',
 '["Both sexes together reflect the image — no human alone fully embodies it","Only men bear the image","Image refers to the soul, not gender","This verse separates image from gender"]','Both sexes together reflect the image — no human alone fully embodies it',
 'The pluralism "male and female" in the same verse as imago Dei shows that the fullness of the image requires both.'),

-- Stage 3
(1,1,3,'Genesis 1 has a structured pattern of Days 1–3 forming spaces and Days 4–6 filling them. What does this structure teach?',
 '["God is a God of order who creates a structured, purposeful universe — not chaos","It is only a literary device with no meaning","The first three days were literally longer","Days 4–6 happened simultaneously with Days 1–3"]','God is a God of order who creates a structured, purposeful universe — not chaos',
 'Days 1 (light/dark) / 4 (luminaries); 2 (sky/sea) / 5 (birds/fish); 3 (land/plants) / 6 (animals/humans) = a creation of order.'),
(1,1,3,'Genesis 1 says God "separated" things (light from darkness, waters above from below, etc.). Why is separation/distinction important to creation?',
 '["Order and meaning require distinction; creation is God imposing meaningful boundaries on chaos","Separation was only a physical necessity","God prefers separation to unity","Separation represents God''s judgment on darkness"]','Order and meaning require distinction; creation is God imposing meaningful boundaries on chaos',
 'The act of distinguishing (havdalah) — day from night, land from sea — is the act of creating meaningful order from formless void.'),
(1,1,3,'Why does Genesis 1 describe God creating by speaking ("God said… and it was so")? What does this reveal about his nature?',
 '["God''s word is creatively powerful — reality conforms to his speech; this anticipates the Word in John 1","Speech was the only tool available","It shows God is distant from creation","Speech means God is non-physical"]','God''s word is creatively powerful — reality conforms to his speech; this anticipates the Word in John 1',
 'Creation by divine speech establishes that God''s word has ultimate authority — a theme echoed in John 1 and throughout Scripture.'),
(1,1,3,'What does the rhythm of evening and morning (each "day") suggest about the nature of the creation days?',
 '["A structured, measured time period marking distinct creative acts — scholars debate literal vs. figurative meaning","They were exactly 24 hours (all traditions agree)","Evening and morning are just poetic language with no time reference","Days prove evolution is false"]','A structured, measured time period marking distinct creative acts — scholars debate literal vs. figurative meaning',
 'Evening-morning is the Hebrew day pattern; debate exists between 24-hour literal days, day-age theory, and literary frameworks.'),
(1,1,3,'The "great sea creatures" (Gen. 1:21) were objects of pagan fear and worship. What is the point of God simply creating them?',
 '["They are part of God''s good creation, not rival divine powers — Genesis demythologizes pagan cosmology","They are dangerous and evil","They are symbols of chaos God fights","They only appear in pagan myths"]','They are part of God''s good creation, not rival divine powers — Genesis demythologizes pagan cosmology',
 'In Canaanite and Babylonian myths, sea monsters (Leviathan/Tiamat) were divine rivals; Genesis says God casually creates them as fish.'),

-- Stage 4
(1,1,4,'How does Genesis 1 implicitly critique ANE (Ancient Near Eastern) cosmologies like Enuma Elish?',
 '["By presenting creation without conflict: no battle with chaos gods, no creation from divine corpse — YHWH creates by sovereign word alone","By borrowing the same structure entirely","By saying the ANE myths were almost correct","By mentioning Babylon by name"]','By presenting creation without conflict: no battle with chaos gods, no creation from divine corpse — YHWH creates by sovereign word alone',
 'Enuma Elish has Marduk killing Tiamat (chaos) to create; Genesis has no battle — YHWH speaks and it is, asserting radical monotheistic sovereignty.'),
(1,1,4,'What are the theological implications of "God rested" (shabat) on Day 7?',
 '["God''s rest is completion and celebration, not exhaustion; Day 7 remains open (no evening-morning), inviting humans into Sabbath rest with God","God was tired","Sabbath means God stopped caring","The seventh day is only about human rest"]','God''s rest is completion and celebration, not exhaustion; Day 7 remains open (no evening-morning), inviting humans into Sabbath rest with God',
 'Day 7 has no closing formula — it is still open; Hebrews 4 says this rest awaits God''s people: it is an eschatological invitation.'),
(1,1,4,'The word Elohim is plural in Hebrew but takes singular verbs in Genesis 1. What does this grammatical tension suggest?',
 '["It hints at a divine complexity within the one God — later developed in Trinitarian theology","It is a grammatical error","It proves God is multiple gods","It is just a way of expressing greatness in Hebrew"]','It hints at a divine complexity within the one God — later developed in Trinitarian theology',
 'The plural noun + singular verb (and "let us make" in v.26) reflects a richness within God that the NT identifies as Trinitarian.'),
(1,1,4,'Why does Genesis 1 present humans as the pinnacle of creation, created last?',
 '["Literary climax — the prior creation prepares the world for its rulers; humans are creation''s goal, not an afterthought","Humans were the least important","They were created last because the materials became available","It was just the order of evolution"]','Literary climax — the prior creation prepares the world for its rulers; humans are creation''s goal, not an afterthought',
 'The ascending order culminates in humans — Day 6''s crown. The world is prepared as a habitation for God''s image-bearers.'),

-- Stage 5
(1,1,5,'How does Genesis 1''s portrayal of creation ex nihilo (from nothing) differ from ANE creation accounts, and what does this imply about God?',
 '["YHWH creates by sovereign will from nothing — no pre-existing material or rival — implying absolute transcendence and omnipotence","Genesis agrees with ANE accounts that creation used existing chaos material","Ex nihilo is a later Christian concept not in Genesis 1","The difference is only stylistic"]','YHWH creates by sovereign will from nothing — no pre-existing material or rival — implying absolute transcendence and omnipotence',
 'ANE gods shape pre-existing matter; Genesis 1:1 implies all things begin with God''s creative act — supporting creatio ex nihilo and divine aseity.'),
(1,1,5,'The "let us make man in our image" (1:26) has been interpreted as: the divine council, a majestic plural, or a Trinitarian hint. Evaluate these options.',
 '["All three have ancient support; the Trinitarian reading became dominant in Christian theology as consistent with NT revelation without reading later doctrine back anachronistically","Only the majestic plural is correct","Trinitarian reading is the only valid one","The divine council reading proves polytheism"]','All three have ancient support; the Trinitarian reading became dominant as consistent with NT revelation without reading later doctrine back anachronistically',
 'Rabbinic tradition favors the divine council or majestic plural; early Christians saw Trinitarian foreshadowing; responsible exegesis acknowledges all and is canonical.'),
(1,1,5,'Imago Dei has been interpreted as structural (reason/moral capacity), functional (ruling over creation), and relational (relating to God). How do these interpretations complement each other?',
 '["The image includes all three: humans are structurally unique, functionally vice-regents, and relationally responsive to God — each facet requires the others","Only the functional view is correct","The structural view is the only biblical one","These are contradictory interpretations"]','The image includes all three: humans are structurally unique, functionally vice-regents, and relationally responsive to God — each facet requires the others',
 'Most contemporary scholars see these as complementary: capacity enables function; function expresses relation; none stands alone.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- GENESIS 2
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(1,2,1,'What did God form man from in Genesis 2?',
 '["Dust from the ground","Water","Light","Clay from a river"]','Dust from the ground',
 '"The Lord God formed the man of dust from the ground" (Gen. 2:7).'),
(1,2,1,'How did God bring man to life?',
 '["He breathed into his nostrils the breath of life","He spoke life into him","He touched him","He poured water on him"]','He breathed into his nostrils the breath of life',
 '"He breathed into his nostrils the breath of life, and the man became a living creature" (Gen. 2:7).'),
(1,2,1,'What was the name of the garden God planted for the man?',
 '["Eden","Paradise","Canaan","Israel"]','Eden',
 '"The Lord God planted a garden in Eden, in the east" (Gen. 2:8).'),
(1,2,1,'What were the two special trees in the garden of Eden?',
 '["The tree of life and the tree of the knowledge of good and evil","The tree of wisdom and the tree of life","The tree of blessing and the tree of curse","The tree of light and the tree of darkness"]','The tree of life and the tree of the knowledge of good and evil',
 'Genesis 2:9 names both special trees.'),
(1,2,1,'What command did God give the man about the tree of knowledge of good and evil?',
 '["You shall not eat of it, for in the day you eat of it you shall surely die","You may eat of it once","Eat of it to gain wisdom","Guard it carefully"]','You shall not eat of it, for in the day you eat of it you shall surely die',
 '"You may surely eat of every tree of the garden, but of the tree of the knowledge of good and evil you shall not eat" (Gen. 2:16–17).'),
(1,2,1,'God said "It is not good that the man should be alone." What did he provide?',
 '["A helper fit for him (a woman)","An angel","Many animals","A companion from the dust"]','A helper fit for him (a woman)',
 '"I will make him a helper fit for him" (Gen. 2:18).'),
(1,2,1,'What did God make the woman from?',
 '["A rib (side) taken from the man","Dust from the ground","A piece of wood","The breath of God"]','A rib (side) taken from the man',
 '"He took one of his ribs… and the rib that the Lord God had taken from the man he made into a woman" (Gen. 2:21–22).'),
(1,2,1,'What did the man say when he first saw the woman?',
 '["This at last is bone of my bones and flesh of my flesh","You are beautiful","God has blessed me","Welcome, helper"]','This at last is bone of my bones and flesh of my flesh',
 '"This at last is bone of my bones and flesh of my flesh; she shall be called Woman" (Gen. 2:23).'),
(1,2,1,'What does Genesis 2:24 say a man shall do when he marries?',
 '["Leave his father and mother, hold fast to his wife, and become one flesh","Bring a gift to God","Invite the community","Ask permission from the elders"]','Leave his father and mother, hold fast to his wife, and become one flesh',
 '"A man shall leave his father and his mother and hold fast to his wife, and they shall become one flesh" (Gen. 2:24).'),
(1,2,1,'How does Genesis 2:25 describe Adam and Eve''s relationship?',
 '["They were naked and not ashamed","They were clothed and happy","They hid from each other","They were afraid"]','They were naked and not ashamed',
 '"And the man and his wife were both naked and were not ashamed" (Gen. 2:25).'),

-- Stage 2
(1,2,2,'What was Adam''s task in the garden?',
 '["To work it and keep it","To rest and worship","To eat and multiply","To study the animals"]','To work it and keep it',
 '"The Lord God took the man and put him in the garden of Eden to work it and keep it" (Gen. 2:15).'),
(1,2,2,'What were the four rivers that flowed from Eden, according to Genesis 2?',
 '["Pishon, Gihon, Tigris (Hiddekel), and Euphrates","Nile, Jordan, Tigris, and Euphrates","Jordan, Kidron, Pishon, and Gihon","Euphrates, Tigris, Nile, and Red Sea"]','Pishon, Gihon, Tigris (Hiddekel), and Euphrates',
 'Genesis 2:11–14 names these four rivers.'),
(1,2,2,'What task did God give Adam regarding the animals?',
 '["To name them","To care for them","To rule over them with an iron hand","To count them"]','To name them',
 '"Out of the ground the Lord God formed every beast of the field… and brought them to the man to see what he would call them" (Gen. 2:19).'),
(1,2,2,'Why was no animal found to be a suitable helper for the man?',
 '["None was fit for him — they were other kinds of creatures","The animals hadn''t been created yet","Adam was too demanding","God hadn''t looked hard enough"]','None was fit for him — they were other kinds of creatures',
 '"But for Adam there was not found a helper fit for him" (Gen. 2:20) — none matched his nature.'),
(1,2,2,'What does "helper fit for him" (ezer kenegdo) suggest about the woman''s role?',
 '["A corresponding, complementary partner who meets what the man lacks — ezer is used of God in Psalms","A lesser, subordinate assistant","An identical copy of Adam","A caretaker with no agency"]','A corresponding, complementary partner who meets what the man lacks — ezer is used of God in Psalms',
 'Ezer (helper) is used of God (Ps. 121:2) and implies strength-in-aid; kenegdo means corresponding to/face to face with.'),
(1,2,2,'How does Genesis 2 transition from the creation of the cosmos (ch. 1) to a more focused account?',
 '["It zooms in on the creation of humanity and the garden — a complementary close-up, not a contradiction","It repeats the same events with minor changes","It contradicts Genesis 1","It is a later addition with no connection"]','It zooms in on the creation of humanity and the garden — a complementary close-up, not a contradiction',
 'Gen. 1 is the wide-angle lens (cosmos); Gen. 2 is the zoom lens (humanity and garden). Together they form a complete picture.'),
(1,2,2,'God put the man to sleep before creating the woman. What does this suggest?',
 '["The woman''s creation is entirely a divine act — the man had no part in making her","Adam was exhausted","It was a surgical necessity only","God hid the process"]','The woman''s creation is entirely a divine act — the man had no part in making her',
 'The deep sleep removes human agency from the woman''s creation, emphasizing she is God''s gift, not human invention.'),
(1,2,2,'The man calls the woman "isha" and himself "ish." What does this word connection show?',
 '["They share the same nature — she is from him and they belong together","It is just a naming convention","It shows the man named her","It has no significance in Hebrew"]','They share the same nature — she is from him and they belong together',
 'In Hebrew, ish (man) and isha (woman) are phonetically linked, expressing ontological unity and kinship.'),
(1,2,2,'What does Genesis 2:24 say about the permanence and priority of marriage?',
 '["A man leaves his family of origin — marriage creates a new primary bond: ''one flesh''","Family bonds are more important than marriage","Marriage is secondary to community","One flesh refers only to physical union"]','A man leaves his family of origin — marriage creates a new primary bond: ''one flesh''',
 'The leaving, cleaving, and becoming one flesh describe a permanent covenant bond surpassing even parent-child ties.'),
(1,2,2,'What might the Tree of Life represent in the garden?',
 '["Sustained communion with and dependence on God — life as a gift continually received","Immortality earned by good behavior","A magic fruit","Physical health alone"]','Sustained communion with and dependence on God — life as a gift continually received',
 'The tree of life appears again in Revelation 22, representing unbroken access to God. Life is always a received gift, not a possession.'),

-- Stage 3 (fewer needed)
(1,2,3,'Genesis 2 presents the garden as a sanctuary where God walks. How does this connect to later temple theology?',
 '["Eden is the first temple — God''s dwelling on earth; the tabernacle/temple are designed to mirror its structure","It is only a garden with no theological significance","Temple theology came much later with no Eden connection","Only Ezekiel connects Eden and the temple"]','Eden is the first temple — God''s dwelling on earth; the tabernacle/temple are designed to mirror its structure',
 'Eden''s east entrance, cherubim guard, and divine presence anticipate the tabernacle layout; humans are created as priests to serve in it.'),
(1,2,3,'What is the significance of the forbidden tree being "in the midst of the garden," freely visible?',
 '["The temptation was real and daily — obedience was a genuine choice, not forced","It was placed there to trap them","God tested them to see if they would fail","It was hidden until the serpent revealed it"]','The temptation was real and daily — obedience was a genuine choice, not forced',
 'The visible, accessible tree makes the command a continuous moral choice — genuine love and obedience require the possibility of disobedience.'),
(1,2,3,'The command "to work and keep" the garden uses the same Hebrew words for Levitical priestly service (abad/shamar). What does this imply?',
 '["Adam and Eve were the first priests — humanity''s vocation is priestly service in God''s presence","These words are unrelated to priesthood","The connection is coincidental","Priesthood came only with Moses"]','Adam and Eve were the first priests — humanity''s vocation is priestly service in God''s presence',
 'Abad (serve) and shamar (guard) in Num. 3:7–8 describe Levitical duties; Genesis sets the pattern: human vocation is priestly.'),
(1,2,3,'How does the "naming of animals" scene demonstrate Adam''s authority and intelligence?',
 '["Naming in Hebrew thought implies authority and understanding of essence; Adam exercises God-delegated rule and wisdom","Names were just arbitrary labels","Animals could have named themselves","God prompted each name"]','Naming in Hebrew thought implies authority and understanding of essence; Adam exercises God-delegated rule and wisdom',
 'In the ancient world, to name is to define and rule; God bringing animals to Adam for naming reflects vice-regency over creation.'),

-- Stage 4
(1,2,4,'How does Genesis 2:25 ("naked and not ashamed") contrast with Genesis 3, and what does the contrast reveal?',
 '["Pre-fall: full transparency and intimacy with no shame; post-fall: shame, hiding, and broken relationship — nakedness becomes vulnerability","It is just a physical description with no theological meaning","Shame came from the serpent not sin","Nakedness was always shameful in Hebrew culture"]','Pre-fall: full transparency and intimacy with no shame; post-fall: shame, hiding, and broken relationship — nakedness becomes vulnerability',
 'The bookend — 2:25 (no shame) vs. 3:7 (saw they were naked) — marks the tragic fall from full relationship to concealment and fear.'),
(1,2,4,'Why does Genesis 2 use YHWH Elohim (LORD God) while Genesis 1 uses Elohim alone?',
 '["Elohim is the transcendent Creator; YHWH Elohim is the covenant God in personal relationship — the combination intensifies both","This proves two different authors","YHWH is a later name for God","It is just a stylistic variation with no meaning"]','Elohim is the transcendent Creator; YHWH Elohim is the covenant God in personal relationship — the combination intensifies both',
 'The divine name shift signals that the same God who created all things now draws near in covenant intimacy — a theological progression.'),

-- Stage 5
(1,2,5,'Marriage as "one flesh" in Genesis 2:24 is quoted by Jesus (Matt. 19:5) and Paul (Eph. 5:31–32). What does this range of NT use reveal?',
 '["It grounds the theology of marriage as covenant, Christ''s union with the church, and the permanence of the marriage bond in creation order rather than cultural convention","It proves marriage is only a legal contract","The NT uses it differently than Genesis intended","It was quoted only to contrast OT and NT"]','It grounds the theology of marriage as covenant, Christ''s union with the church, and the permanence of the marriage bond in creation order rather than cultural convention',
 'Jesus uses it for permanence; Paul uses it for Christ/church typology; both ground ethical norms in creation, not tradition.'),
(1,2,5,'How does the creation of woman from man''s rib/side (tsela) function both biologically and theologically in Genesis 2?',
 '["Biologically it asserts common humanity; theologically it shows she is not a servant made from the foot or a master from the head, but an equal partner from his side","It only makes a biological point","It is purely symbolic with no concrete meaning","It shows women are physically weaker"]','Biologically it asserts common humanity; theologically it shows she is not a servant made from the foot or a master from the head, but an equal partner from his side',
 'Tsela (side/rib) is used elsewhere for equal structural components; the traditional interpretation of "equal beside him" carries strong exegetical support.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- GENESIS 3
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(1,3,1,'Who tempted Eve in the garden?',
 '["The serpent","An angel","Adam","A stranger"]','The serpent',
 '"The serpent was more crafty than any other beast of the field" (Gen. 3:1).'),
(1,3,1,'What did the serpent question first when speaking to Eve?',
 '["Did God actually say you shall not eat of any tree in the garden?","You will not die","God is hiding something from you","Why do you follow God''s commands?"]','Did God actually say you shall not eat of any tree in the garden?',
 'The serpent began by distorting and questioning God''s word (Gen. 3:1).'),
(1,3,1,'What did the serpent promise Eve would happen if she ate the fruit?',
 '["She would not die but would be like God, knowing good and evil","She would gain magical powers","She would rule over all animals","She would live forever"]','She would not die but would be like God, knowing good and evil',
 '"You will not surely die… you will be like God, knowing good and evil" (Gen. 3:4–5).'),
(1,3,1,'What did Adam and Eve do after eating the forbidden fruit?',
 '["They realized they were naked and sewed fig leaf coverings","They ran away from God","They asked God for forgiveness","They fell asleep"]','They realized they were naked and sewed fig leaf coverings',
 '"The eyes of both were opened, and they knew that they were naked… they sewed fig leaves together" (Gen. 3:7).'),
(1,3,1,'Where did Adam and Eve hide when they heard God walking in the garden?',
 '["Among the trees of the garden","Behind a large rock","In a cave","Under the water"]','Among the trees of the garden',
 '"They heard the sound of the Lord God walking in the garden… and the man and his wife hid among the trees" (Gen. 3:8).'),
(1,3,1,'What question did God ask Adam first?',
 '["Where are you?","Did you eat the fruit?","Who told you that you were naked?","What have you done?"]','Where are you?',
 '"The Lord God called to the man and said to him, Where are you?" (Gen. 3:9).'),
(1,3,1,'Who did Adam blame for eating the fruit?',
 '["The woman God gave him","Only himself","The serpent","God directly"]','The woman God gave him',
 '"The woman whom you gave to be with me, she gave me fruit of the tree, and I ate" (Gen. 3:12).'),
(1,3,1,'Who did Eve blame for eating the fruit?',
 '["The serpent","Adam","God","Herself"]','The serpent',
 '"The serpent deceived me, and I ate" (Gen. 3:13).'),
(1,3,1,'What did God curse as a result of Adam''s sin?',
 '["The ground","The serpent only","The sky","All animals"]','The ground',
 '"Cursed is the ground because of you; in pain you shall eat of it all the days of your life" (Gen. 3:17).'),
(1,3,1,'What clothing did God make for Adam and Eve?',
 '["Garments of skin","Woven cloth","Leaves sewn together","Wool from sheep"]','Garments of skin',
 '"The Lord God made for Adam and for his wife garments of skins and clothed them" (Gen. 3:21).'),

-- Stage 2
(1,3,2,'What does God say in Genesis 3:15 about the serpent and the woman''s offspring?',
 '["He will bruise your head, and you shall bruise his heel","You will fight forever with no winner","The woman will rule over you","Your offspring will be cursed"]','He will bruise your head, and you shall bruise his heel',
 '"I will put enmity between you and the woman… he shall bruise your head, and you shall bruise his heel" (Gen. 3:15).'),
(1,3,2,'What does God tell Eve will be multiplied as a result of her sin?',
 '["Her pain in childbearing","Her years of life","Her work in the garden","Her offspring"]','Her pain in childbearing',
 '"I will surely multiply your pain in childbearing; in pain you shall bring forth children" (Gen. 3:16).'),
(1,3,2,'Why did God ban Adam and Eve from the garden?',
 '["To prevent them from eating the tree of life and living forever in a fallen state","As punishment only","Because they no longer deserved it","Because they asked to leave"]','To prevent them from eating the tree of life and living forever in a fallen state',
 '"He must not reach out his hand and take also from the tree of life and eat, and live forever" (Gen. 3:22).'),
(1,3,2,'What did God place east of Eden to guard the tree of life?',
 '["Cherubim and a flaming, turning sword","An angel alone","A wall of fire","A great river"]','Cherubim and a flaming, turning sword',
 '"He placed the cherubim and a flaming sword that turned every way to guard the way to the tree of life" (Gen. 3:24).'),
(1,3,2,'What was Adam told would be the result of his sin regarding his work?',
 '["The ground would produce thorns and thistles; by sweat and toil he would eat until he returned to dust","He would never eat again","He would work for God forever","The ground would swallow him"]','The ground would produce thorns and thistles; by sweat and toil he would eat until he returned to dust',
 'Gen. 3:17–19 describes thorns, painful toil, and death — "till you return to the ground."'),
(1,3,2,'What name did Adam give his wife after God''s judgment, and what did it mean?',
 '["Eve — because she was the mother of all living","Sarah — princess","Woman — because she came from man","Life — the gift of God"]','Eve — because she was the mother of all living',
 '"The man called his wife''s name Eve, because she was the mother of all living" (Gen. 3:20).'),
(1,3,2,'The serpent told Eve she would "be like God." What was the real nature of this temptation?',
 '["Autonomy — defining good and evil for herself rather than trusting God''s definition","Physical beauty","Worldly power","Intellectual knowledge for its own sake"]','Autonomy — defining good and evil for herself rather than trusting God''s definition',
 'The temptation was to become the arbiter of morality, replacing God''s authority with self-determination.'),
(1,3,2,'Why is it significant that Adam was "with her" (Gen. 3:6) when Eve ate?',
 '["It shows Adam''s passive failure — he did not protect her or intervene, making him complicit","It proves Adam did not know what was happening","It shows they always made decisions together","It only means they were in the same garden"]','It shows Adam''s passive failure — he did not protect or intervene, making him complicit',
 '"She also gave some to her husband who was with her, and he ate" — Adam''s silence and passivity are as culpable as the eating.'),
(1,3,2,'What does God''s question "Where are you?" demonstrate about the nature of God''s relationship with humanity post-fall?',
 '["God pursues the hiding sinner — he initiates the relationship even after they flee","God didn''t know where they were","It was a test of their honesty","It is a rhetorical question with no theological weight"]','God pursues the hiding sinner — he initiates the relationship even after they flee',
 'The pursuing question shows divine grace: God seeks the fallen humans before they seek him — a pattern throughout Scripture.'),
(1,3,2,'How does God''s provision of skin garments (3:21) foreshadow the sacrificial system?',
 '["An animal had to die to cover their shame — blood was shed for covering sin, anticipating atonement","The garments were just practical","God simply made the clothing supernaturally","It only showed God''s mercy without blood"]','An animal had to die to cover their shame — blood was shed for covering sin, anticipating atonement',
 'The skin garments imply an animal''s death — an early picture that covering sin requires the shedding of blood (Heb. 9:22).'),

-- Stage 3
(1,3,3,'Genesis 3:15 is called the "protoevangelium" (first gospel). Why?',
 '["It is the first promise of a coming deliverer who will crush the serpent — the seed of the woman points to Christ","It is just a statement of enmity between humans and snakes","It is only a curse on the serpent","The word gospel doesn''t appear until the NT"]','It is the first promise of a coming deliverer who will crush the serpent — the seed of the woman points to Christ',
 'Seed of the woman (unusual — seed is male) hints at a miraculous birth; the head/heel language anticipates Christ''s victory through death.'),
(1,3,3,'How does the blame-shifting (Adam→woman→serpent) reveal the moral effects of the fall?',
 '["Sin destroys human integrity and relational harmony; the fall produces self-justification and broken community","It is just psychological defensiveness","Only Eve and the serpent were to blame","Blame-shifting is natural behavior, not sinful"]','Sin destroys human integrity and relational harmony; the fall produces self-justification and broken community',
 'The cascade of blame shows sin''s relational destruction: human-divine, husband-wife, human-creation relationships are all broken.'),
(1,3,3,'Why does Paul write in Romans 5 that sin entered through one man (Adam) rather than through Eve who ate first?',
 '["Adam was the covenant head — representative humanity; his sin counted federally for all; Eve was deceived but Adam acted knowingly","Because Paul forgot Eve ate first","Because women can''t be covenant heads","Because Paul was culturally biased"]','Adam was the covenant head — representative humanity; his sin counted federally for all; Eve was deceived but Adam acted knowingly',
 'Federal headship: Adam as representative of humanity means his sin''s consequences fall on all; Paul also notes Eve was deceived (1 Tim. 2:14).'),
(1,3,3,'How does the structure of Genesis 3 mirror a court proceeding?',
 '["God questions each party in order (man, woman, serpent) before passing sentence — it is an orderly divine judgment","It is just a narrative","God acted impulsively","The verdicts came before the questioning"]','God questions each party in order (man, woman, serpent) before passing sentence — it is an orderly divine judgment',
 'The interrogation sequence, each party answering, followed by measured verdicts reflects God''s justice: fair process before punishment.'),

-- Stage 4
(1,3,4,'How does Genesis 3 illustrate the structure of all temptation according to 1 John 2:16 (lust of eyes, lust of flesh, pride of life)?',
 '["The fruit was good for food (flesh), pleasing to the eye (eyes), desirable to make one wise (pride) — the passage anticipates John''s taxonomy","This is coincidental","1 John is about something different","Only pride is relevant here"]','The fruit was good for food (flesh), pleasing to the eye (eyes), desirable to make one wise (pride) — the passage anticipates John''s taxonomy',
 'Gen. 3:6 and 1 John 2:16 share identical categories: appetite, aesthetics, and pride — showing the consistency of temptation''s structure.'),
(1,3,4,'How does Christ as the "last Adam" (1 Cor. 15:45) succeed where the first Adam failed, using Genesis 3 parallels?',
 '["In a garden (Gethsemane), Christ resisted temptation and accepted death; on a tree (cross) he bore the curse; his obedience undoes Adam''s disobedience","Christ simply did more miracles","The parallel is only metaphorical","Only Paul makes this connection without biblical basis"]','In a garden (Gethsemane), Christ resisted temptation and accepted death; on a tree (cross) he bore the curse; his obedience undoes Adam''s disobedience',
 'Rom. 5:12–21 makes the Adam-Christ typology explicit: one man''s disobedience = death; one man''s obedience = life.'),

-- Stage 5
(1,3,5,'Genesis 3 is foundational to the Christian doctrine of "original sin." How did Augustine develop this from the text, and what are the textual and theological limits of his reading?',
 '["Augustine correctly identified the fall as the source of human sinfulness inherited through generation; the text supports a fractured human nature, though Augustine''s specific guilt-transmission mechanism goes beyond explicit textual claims","Augustine invented original sin with no biblical basis","The text teaches only individual sin, not inheritance","Original sin is explicit in Genesis 3 without interpretation"]','Augustine correctly identified the fall as the source of human sinfulness inherited through generation; the text supports a fractured human nature, though Augustine''s specific guilt-transmission mechanism goes beyond explicit textual claims',
 'Genesis 3 clearly shows a cosmic rupture; Romans 5 develops federal headship; Augustine extended to inherited guilt — a legitimate but debated theological inference.'),
(1,3,5,'The expulsion from Eden results in loss of access to the tree of life. How does Revelation 22 reverse this, and what does the structure reveal about biblical theology?',
 '["Revelation 22 restores access to the tree of life in the New Jerusalem — the Bible''s arc moves from creation and fall to new creation and full restoration","Revelation 22 is unrelated to Genesis 3","The tree of life is only symbolic in Revelation","The expulsion was permanent with no reversal"]','Revelation 22 restores access to the tree of life in the New Jerusalem — the Bible''s arc moves from creation and fall to new creation and full restoration',
 'Genesis 3 closes the garden; Revelation 22 reopens it. The entire canon is the story of redemption between these two acts — biblical theology as creation-fall-redemption-new creation.'),
(1,3,5,'The serpent tells Eve "you will be like God." How does this compare with Philippians 2:6, where Christ "did not count equality with God a thing to be grasped"?',
 '["The contrast is the heart of salvation: Adam/Eve grasped at divine status and fell; Christ, truly God, did not grasp but emptied himself — the antidote to the first sin","Philippians 2 has no connection to Genesis 3","Both are about the same kind of pride in different contexts","Christ also wanted to be like God"]','The contrast is the heart of salvation: Adam/Eve grasped at divine status and fell; Christ, truly God, did not grasp but emptied himself — the antidote to the first sin',
 'The "grasping" in Gen. 3 vs. the "not grasping" in Phil. 2:6 is one of the Bible''s deepest theological contrasts: the humility of Christ reverses the pride of the fall.')

ON CONFLICT DO NOTHING;


-- ============================================================================
-- ROMANS 1
-- ============================================================================

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation) VALUES

-- Stage 1
(45,1,1,'Who wrote the book of Romans?',
 '["Paul (a servant of Christ Jesus)","Peter","Luke","Barnabas"]','Paul (a servant of Christ Jesus)',
 'Romans 1:1 identifies the author as "Paul, a servant of Christ Jesus."'),
(45,1,1,'What is the theme verse of Romans, according to Romans 1:16–17?',
 '["The gospel is the power of God for salvation to everyone who believes; in it the righteousness of God is revealed","God loves the world and sent his Son","We are all sinners in need of grace","Faith without works is dead"]','The gospel is the power of God for salvation to everyone who believes; in it the righteousness of God is revealed',
 'Romans 1:16–17 is widely recognized as Paul''s theme statement for the entire letter.'),
(45,1,1,'Paul says he was set apart for the gospel. Where does Romans 1:2 say this gospel was promised?',
 '["In the holy Scriptures (through the prophets)","In a vision to Paul","At Paul''s birth","At the Council of Jerusalem"]','In the holy Scriptures (through the prophets)',
 '"Which he promised beforehand through his prophets in the holy Scriptures" (Rom. 1:2).'),
(45,1,1,'How does Paul describe himself at the opening of Romans?',
 '["A servant of Christ Jesus, called to be an apostle, set apart for the gospel of God","The greatest of all apostles","A prophet sent to Rome","A teacher of the law"]','A servant of Christ Jesus, called to be an apostle, set apart for the gospel of God',
 'Romans 1:1 is Paul''s self-introduction.'),
(45,1,1,'Paul says he is "not ashamed of the gospel." Why?',
 '["Because it is the power of God for salvation to everyone who believes","Because he earned it through hard work","Because it is popular","Because the Romans already knew it"]','Because it is the power of God for salvation to everyone who believes',
 '"For I am not ashamed of the gospel, for it is the power of God for salvation to everyone who believes" (Rom. 1:16).'),
(45,1,1,'According to Romans 1:20, what can be clearly seen from creation?',
 '["God''s invisible attributes — his eternal power and divine nature","Only that God exists","The moral law","The plan of salvation"]','God''s invisible attributes — his eternal power and divine nature',
 '"His invisible attributes, namely, his eternal power and divine nature, have been clearly perceived… in the things that have been made" (Rom. 1:20).'),
(45,1,1,'What does Paul say people did with their knowledge of God in Romans 1:21?',
 '["They did not honor him or give thanks but became futile in their thinking","They sought God earnestly","They worshiped him in ignorance","They waited for further revelation"]','They did not honor him or give thanks but became futile in their thinking',
 '"For although they knew God, they did not honor him as God or give thanks to him" (Rom. 1:21).'),
(45,1,1,'What does Paul say people who claimed to be wise in Romans 1:22 actually became?',
 '["Fools","Philosophers","Wise in a new way","Humble"]','Fools',
 '"Claiming to be wise, they became fools" (Rom. 1:22).'),
(45,1,1,'Paul says the wrath of God is revealed from heaven against what?',
 '["All ungodliness and unrighteousness of men who suppress the truth","Only the worst sins","The Romans specifically","Those who have not heard the gospel"]','All ungodliness and unrighteousness of men who suppress the truth',
 '"The wrath of God is revealed from heaven against all ungodliness and unrighteousness of men who by their unrighteousness suppress the truth" (Rom. 1:18).'),
(45,1,1,'Paul says he is eager to preach the gospel at Rome. What does he call himself in relation to all people?',
 '["Under obligation (debtor) to both Greeks and barbarians","Superior to others","The founder of the Roman church","A visitor only"]','Under obligation (debtor) to both Greeks and barbarians',
 '"I am under obligation both to Greeks and to barbarians, both to the wise and to the foolish" (Rom. 1:14).'),

-- Stage 2
(45,1,2,'How does Romans 1:17 describe justification?',
 '["From faith for faith (from faith to faith)","By works and faith combined","Through the law","By circumcision and faith"]','From faith for faith (from faith to faith)',
 '"For in it the righteousness of God is revealed from faith for faith, as it is written, The righteous shall live by faith" (Rom. 1:17).'),
(45,1,2,'What OT verse does Paul quote in Romans 1:17 to support justification by faith?',
 '["Habakkuk 2:4 — The righteous shall live by faith","Deuteronomy 6:4","Genesis 15:6","Isaiah 53:11"]','Habakkuk 2:4 — The righteous shall live by faith',
 'Paul quotes Habakkuk 2:4, a key text for the Reformation doctrine of justification by faith alone.'),
(45,1,2,'Paul says he is not ashamed of the gospel for both Jews and Greeks. What does "to the Jew first and also to the Greek" mean?',
 '["Salvation is for all people; but God''s redemptive history moved through Israel first — a priority of sequence, not exclusivity","Jews are more important to God","Greeks receive salvation differently","It is only a greeting formula"]','Salvation is for all people; but God''s redemptive history moved through Israel first — a priority of sequence, not exclusivity',
 '"To the Jew first and also to the Greek" (1:16) reflects salvation-historical priority — the gospel went to the Jew first (Acts pattern).'),
(45,1,2,'Romans 1:20 says people are "without excuse." What made them inexcusable?',
 '["General revelation in creation clearly shows God''s eternal power and nature","They had Scripture","An angel visited them","They were told verbally"]','General revelation in creation clearly shows God''s eternal power and nature',
 'Creation itself is sufficient revelation of God''s existence and power; rejecting this leaves no excuse.'),
(45,1,2,'Paul describes three exchanges in Romans 1 that characterize the fall. What is the first exchange?',
 '["They exchanged the glory of the immortal God for images of created things","They exchanged truth for love","They exchanged worship for wisdom","They exchanged good deeds for pleasure"]','They exchanged the glory of the immortal God for images of created things',
 '"They exchanged the glory of the immortal God for images resembling mortal man and birds and animals and creeping things" (Rom. 1:23).'),
(45,1,2,'What phrase does Paul repeat three times to describe God''s response to human sin in Romans 1?',
 '["God gave them up","God was angry","God withdrew his Spirit","God sent punishment"]','God gave them up',
 '"God gave them up" appears in Romans 1:24, 1:26, and 1:28 — a judicial act of abandonment.'),
(45,1,2,'Romans 1:25 describes the second exchange. What was exchanged?',
 '["The truth about God for a lie, and they worshiped the creature rather than the Creator","Wisdom for foolishness","Freedom for slavery","Prayer for silence"]','The truth about God for a lie, and they worshiped the creature rather than the Creator',
 '"They exchanged the truth about God for a lie and worshiped and served the creature rather than the Creator" (Rom. 1:25).'),
(45,1,2,'Paul mentions he has been prevented many times from visiting Rome. What is his stated desire?',
 '["To impart some spiritual gift to strengthen them and to be mutually encouraged","To correct their theology","To establish authority over their church","To collect money for Jerusalem"]','To impart some spiritual gift to strengthen them and to be mutually encouraged',
 '"I long to see you, that I may impart to you some spiritual gift to strengthen you — that is, that we may be mutually encouraged" (Rom. 1:11–12).'),
(45,1,2,'Paul says in Romans 1:5 he received grace and apostleship to bring about what?',
 '["The obedience of faith among all nations for the sake of Christ''s name","The conversion of all Jews","His own vindication","The collection for Jerusalem"]','The obedience of faith among all nations for the sake of Christ''s name',
 '"Through whom we have received grace and apostleship to bring about the obedience of faith for the sake of his name among all the nations" (Rom. 1:5).'),
(45,1,2,'Paul calls the Roman Christians "beloved of God… called to be saints." What does "saints" (hagioi) mean?',
 '["Holy ones — set apart by God, not individuals who achieved sainthood","Especially virtuous people","Church leaders only","The twelve apostles"]','Holy ones — set apart by God, not individuals who achieved sainthood',
 'Hagioi means holy ones — all believers are called saints, not by their perfection but by God''s call and designation.'),

-- Stage 3
(45,1,3,'What does Paul mean by "the righteousness of God" revealed in the gospel (Rom. 1:17)?',
 '["God''s own righteous character expressed as saving activity — a righteousness he gives to faith, not just a standard of judgment","God''s punishment of sinners only","A quality humans earn through obedience","A legal standard unrelated to salvation"]','God''s own righteous character expressed as saving activity — a righteousness he gives to faith, not just a standard of judgment',
 'Dikaiosyne Theou (righteousness of God) is both what God is and what he gives; the gospel reveals both his justice and his justifying grace.'),
(45,1,3,'How does Paul''s argument in Romans 1:18–32 build his case for universal sinfulness in the letter?',
 '["He shows Gentiles without Scripture are guilty through suppressed natural revelation — this is step 1 of 3; ch. 2 addresses self-righteous Gentiles; ch. 2–3 address Jews — all are guilty","He only argues Gentiles are sinful","He proves Jews are more sinful","This section is unrelated to the rest of Romans"]','He shows Gentiles without Scripture are guilty through suppressed natural revelation — this is step 1 of 3; ch. 2 addresses self-righteous Gentiles; ch. 2–3 address Jews — all are guilty',
 'Romans 1–3 is a systematic courtroom demonstration that "no one is righteous" — Gentiles first (1:18–32), then moralists (2:1–16), then Jews (2:17–3:20).'),
(45,1,3,'What is "general revelation" according to Romans 1:19–20, and what are its limits?',
 '["Creation reveals God''s eternal power and divine nature — enough to leave humans without excuse but insufficient for saving knowledge without special revelation","Creation reveals everything needed for salvation","General revelation saves people who follow it","Natural revelation is unreliable"]','Creation reveals God''s eternal power and divine nature — enough to leave humans without excuse but insufficient for saving knowledge without special revelation',
 'General revelation establishes accountability (no excuse) but not salvation — saving knowledge requires the gospel (the "special revelation" Paul is heralding).'),
(45,1,3,'The "three exchanges" in Romans 1 (vv.23, 25, 26–27) follow a consistent pattern. What does this pattern reveal?',
 '["Sin is the progressive inversion of creation order: worship redirected from Creator to creature, leading to moral disorder at every level","Sin is only about sexual immorality","The exchanges are independent, unrelated acts","Paul describes three different people groups"]','Sin is the progressive inversion of creation order: worship redirected from Creator to creature, leading to moral disorder at every level',
 'Each exchange mirrors creation inversion: the idol-worship exchange leads to ethical disorder — idolatry is not only about what you worship but about what you become.'),

-- Stage 4
(45,1,4,'How does Paul''s description of "God gave them up" (three times) relate to the OT concept of divine wrath?',
 '["It reflects the wrath of abandonment — God withdrawing his restraining grace as a judicial act, not impulsive anger","It means God stopped caring","It is only a passive description","This is a NT concept with no OT basis"]','It reflects the wrath of abandonment — God withdrawing his restraining grace as a judicial act, not impulsive anger',
 'The three-fold "gave them up" mirrors OT patterns of God "hiding his face"; wrath here is structured and judicial, not arbitrary.'),
(45,1,4,'Romans 1:3–4 presents a two-stage Christology: "descended from David" and "declared Son of God by the resurrection." How should we understand this without implying Jesus became divine at the resurrection?',
 '["The two stages describe his humiliation (incarnate as David''s seed) and vindication (powerful Sonship confirmed by resurrection) — both stages reveal who he always was","Jesus became God''s Son only at the resurrection","Romans 1:4 proves adoptionism","The resurrection is unrelated to Jesus''s divine Sonship"]','The two stages describe his humiliation (incarnate as David''s seed) and vindication (powerful Sonship confirmed by resurrection) — both stages reveal who he always was',
 'Paul uses a pre-existing creed; kata sarka / kata pneuma (according to flesh/Spirit) contrasts modes of existence, not two natures achieved in sequence.'),
(45,1,4,'Paul says he is "set apart for the gospel of God" (1:1) — the same language used of Israel (Isaiah 49) and the Pharisees (perushim = set apart). What is Paul''s point?',
 '["His calling mirrors Israel''s calling — he is the representative Jew through whom God''s redemptive purposes extend to the nations","He is contrasting himself with Pharisees","The language is coincidental","Paul was rejecting his Jewish identity"]','His calling mirrors Israel''s calling — he is the representative Jew through whom God''s redemptive purposes extend to the nations',
 'Paul redefines "set apart" from ethnic/ritual separation (Pharisee) to mission-for-the-nations (Isaiah 49:1–6) — he is the faithful Israel in miniature.'),

-- Stage 5
(45,1,5,'Romans 1:17 quotes Habakkuk 2:4: "The righteous shall live by faith." Paul uses this as the thesis of justification by faith. How does this read Habakkuk in context?',
 '["In Habakkuk, the righteous live by faithfulness/trust amid God''s judgment; Paul extends this to soteriological justification — a legitimate typological/canonical reading","Paul misreads Habakkuk entirely","Habakkuk only speaks of national survival","The Hebrew and Greek meanings are identical without any extension"]','In Habakkuk, the righteous live by faithfulness/trust amid God''s judgment; Paul extends this to soteriological justification — a legitimate typological/canonical reading',
 'Habakkuk''s emunah (faithfulness) and Paul''s pistis (faith) are related; Paul applies the pattern canonically — the same faith that sustained Israel in crisis justifies the sinner before God.'),
(45,1,5,'Paul''s three-fold "God gave them up" in Romans 1 has been called the "wrath of abandonment." How does this relate to the cross, where God "gave up" his own Son?',
 '["The cross is the supreme act of abandonment — God gave his Son over to the very judgment humanity deserved, reversing the wrath of abandonment through Christ''s bearing of it","The two uses of ''give up'' are unrelated","The cross is only about love, not wrath","Romans 8:32 uses different language"]','The cross is the supreme act of abandonment — God gave his Son over to the very judgment humanity deserved, reversing the wrath of abandonment through Christ''s bearing of it',
 'Romans 8:32 ("he did not spare his own Son but gave him up for us all") uses the same paradidomi language — the wrath of abandonment fell on Christ so it need not fall on us.'),
(45,1,5,'How does the "obedience of faith" (1:5) function as a frame for the entire letter of Romans (see also 16:26)?',
 '["It is the bookending purpose statement: the goal of the gospel is not just intellectual belief but a faith that transforms behavior — Paul will develop both justification and sanctification in the letter","It refers only to the initial act of believing","Paul forgot to explain what it means","It is only an introductory courtesy"]','It is the bookending purpose statement: the goal of the gospel is not just intellectual belief but a faith that transforms behavior — Paul will develop both justification and sanctification in the letter',
 '"Obedience of faith" (hypakoē pisteōs) bookends the letter (1:5; 16:26); Paul develops both forensic justification and the Spirit-empowered life of obedience.')

ON CONFLICT DO NOTHING;
